    filters.value = {
      q: '',
      category: '',
      preset: 'any',
      from: null,
      to: null,
    }
    page.value = 1
    cursorByPage.value = { 1: null }
  }

  return {
    viewMode,
    setViewMode,
    filters,
    page,
    articles,
    filteredArticles,
    nextPageCursor,
    totalResults,
    loadingList,
    errorList,
    cursorByPage,
    syncFromRoute,
    fetchListForCurrentRoute,
    fetchDetail,
    getDetailState,
    clearFilters,
  }
})
